content:
/* TempleOS-inspired system theme */

html, body, * {
    font-family: "Courier New", monospace;
    color: #ffb000; /* signature TempleOS amber/orange */
}

/* Core theme variables */
.dark {
    --bg-primary: #000000;
    --bg-secondary: #000000;
    --bg-tertiary: #050505;
    --bg-hover: #111111;
    --bg-selected: #1a1a1a;
    --bg-card: #000000;

    --avatar-bg: #111111;
    --avatar-text: #ffb000;

    --border-primary: #2a2a2a;
    --border-secondary: #1a1a1a;
    --border-thread-divider: #2a2a2a;

    --text-primary: #ffb000;   /* main TempleOS orange */
    --text-secondary: #ffcc66;
    --text-tertiary: #c78a00;
    --text-muted: #7a5a00;

    --indicator-bg: #000000;
    --indicator-border: #ffb000;

    --sidebar-bg: #000000;
    --sidebar-hover: #111111;

    --modal-bg: #000000;
    --modal-overlay: rgba(0, 0, 0, 0.95);

    --dropdown-bg: #000000;
    --dropdown-hover: #111111;

    --input-bg: #000000;
    --input-border: #ffb000;

    --color-danger: #ff3b30;
    --color-warning: #ff9500;
    --color-success: #34c759;
    --color-info: #5ac8fa;

    --background: #000000;
    --foreground: #ffb000;

    --card: #000000;
    --card-foreground: #ffb000;

    --popover: #000000;
    --popover-foreground: #ffb000;

    --primary: #ffb000;
    --primary-foreground: #000000;

    --secondary: #111111;
    --secondary-foreground: #ffb000;

    --muted: #111111;
    --muted-foreground: #c78a00;

    --accent: #111111;
    --accent-foreground: #ffb000;

    --destructive: #ff3b30;

    --border: #2a2a2a;
    --input: #111111;
    --ring: #ffb000;

    --chart-1: #ffb000;
    --chart-2: #ff9500;
    --chart-3: #ffcc66;
    --chart-4: #c78a00;
    --chart-5: #7a5a00;

    --sidebar: #000000;
    --sidebar-foreground: #ffb000;
    --sidebar-primary: #000000;
    --sidebar-primary-foreground: #ffb000;
    --sidebar-accent: #111111;
    --sidebar-accent-foreground: #ffb000;
    --sidebar-border: #2a2a2a;
    --sidebar-ring: #ffb000;

    --thread-card-bg: #000000;
    --thread-card-bg-hover: #111111;
    --thread-card-border: #2a2a2a;

    --thread-header-bg: #000000;
    --thread-content-bg: #000000;
}

::-webkit-scrollbar {
  width: 10px;
  height: 10px;
}

::-webkit-scrollbar-button {
  display: none;
}

::-webkit-scrollbar-track {
  background: #000000;
}

::-webkit-scrollbar-thumb {
  background-color: #ffb000; /* TempleOS orange */
  border-radius: 0px; /* no modern rounding */
  border: 1px solid #2a2a2a;
}

::-webkit-scrollbar-thumb:hover {
  background-color: #ffcc66;
}

img[alt="Aster"],
img[alt="Mail"] {
    filter: sepia(1) saturate(8) hue-rotate(0deg) brightness(1.2);
}


.dark .aster_btn_depth {
    background-image: none;
    background-color: #ffb000;
   
}


.aster_btn span  {
    color:#000000
}
